import{_ as t,c as d,a0 as o,o as c}from"./chunks/framework.B6JXc2q-.js";const _=JSON.parse('{"title":"开发者指南（Contributor Guide）","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/contributor_guide.md","filePath":"architecture/contributor_guide.md"}'),r={name:"architecture/contributor_guide.md"};function i(a,e,s,l,p,n){return c(),d("div",null,e[0]||(e[0]=[o('<h1 id="开发者指南-contributor-guide" tabindex="-1">开发者指南（Contributor Guide） <a class="header-anchor" href="#开发者指南-contributor-guide" aria-label="Permalink to &quot;开发者指南（Contributor Guide）&quot;">​</a></h1><p>版本：v1.0 状态：正式开发规则 最后更新：2026-03-28</p><p>本文档是所有开发改动（包括 AI 执行）的前置规则入口。<strong>在改任何代码之前，必须先确认归属边界并阅读对应文档。</strong></p><hr><h2 id="_1-改动前置规则总表" tabindex="-1">1. 改动前置规则总表 <a class="header-anchor" href="#_1-改动前置规则总表" aria-label="Permalink to &quot;1. 改动前置规则总表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>改动类型</th><th>改动前必须阅读</th><th>改动后必须同步更新</th></tr></thead><tbody><tr><td>改 API（新增/修改接口）</td><td><code>docs/api/api_v1_spec.md</code>、<code>docs/architecture/system_overview.md</code></td><td><code>docs/api/api_v1_spec.md</code></td></tr><tr><td>改播放状态字段或语义</td><td><code>docs/spec/player_state_projection_spec.md</code>、<code>docs/api/api_v1_spec.md</code></td><td><code>docs/spec/player_state_projection_spec.md</code></td></tr><tr><td>改 SSE 推送行为</td><td><code>docs/spec/player_stream_sse_spec.md</code>、<code>docs/spec/player_state_projection_spec.md</code></td><td><code>docs/spec/player_stream_sse_spec.md</code></td></tr><tr><td>改 runtime / XiaoMusic 类</td><td><code>docs/architecture/runtime_architecture.md</code>、<code>docs/spec/runtime_specification.md</code></td><td>视改动范围更新对应规范</td></tr><tr><td>改 playback / facade / coordinator</td><td><code>docs/spec/playback_coordinator_interface.md</code>、<code>docs/spec/player_state_projection_spec.md</code></td><td>视改动范围更新对应规范</td></tr><tr><td>改 auth 相关</td><td><code>docs/authentication_architecture.md</code>、<code>docs/spec/auth_runtime_recovery.md</code></td><td>视改动范围更新对应规范</td></tr><tr><td>改 source / 新增 source 插件</td><td><code>docs/architecture/source_architecture.md</code>、<code>docs/spec/runtime_specification.md</code></td><td><code>docs/architecture/source_architecture.md</code>（若新增来源类型）</td></tr><tr><td>改 WebUI 状态消费逻辑</td><td><code>docs/spec/webui_playback_state_machine_spec.md</code>、<code>docs/spec/player_state_projection_spec.md</code></td><td><code>docs/spec/webui_playback_state_machine_mapping.md</code>（若改了实现结构）</td></tr><tr><td>改 WebUI 接口依赖</td><td><code>docs/architecture/webui_architecture.md</code>、<code>docs/api/api_v1_spec.md</code></td><td><code>docs/architecture/webui_architecture.md</code></td></tr><tr><td>新增任意模块</td><td><code>docs/architecture/system_overview.md</code>（确认归属边界）</td><td>视归属边界更新对应架构文档</td></tr></tbody></table><hr><h2 id="_2-改-api-前" tabindex="-1">2. 改 API 前 <a class="header-anchor" href="#_2-改-api-前" aria-label="Permalink to &quot;2. 改 API 前&quot;">​</a></h2><p>必须确认：</p><ol><li>该接口是否已在 <code>api_v1_spec.md</code> 白名单中？若否，评估是否满足 v1 准入标准（第 3.5 节）。不满足准入标准的接口不得进入 v1，应归为 Internal API 或不新增。</li><li>该接口属于 Class A / B / C 中的哪类？Class A 必须进入统一调度链路，成功响应必须含 <code>transport</code>；Class B 本地控制路径，不得假设 <code>transport</code>；Class C 只读查询，提供统一 envelope 与结构化错误。</li><li>成功响应字段是否符合对应 Class 的契约矩阵？</li><li>错误响应是否使用统一 envelope 加合法 <code>stage</code> 枚举值？</li></ol><p>改动后必须更新 <code>api_v1_spec.md</code>，包括接口白名单、归属总表、逐项契约。</p><hr><h2 id="_3-改-runtime-前" tabindex="-1">3. 改 Runtime 前 <a class="header-anchor" href="#_3-改-runtime-前" aria-label="Permalink to &quot;3. 改 Runtime 前&quot;">​</a></h2><p>必须确认：</p><ol><li>该改动是否涉及子系统的启动顺序或依赖注入？若是，核查 <code>runtime_architecture.md</code> 的生命周期说明。</li><li>该改动是否影响 <code>api</code> 层通过 <code>runtime_provider</code> 访问 runtime 的方式？若是，需同步修改 <code>dependencies.py</code> 的注入点。</li><li>该改动是否将原本属于 <code>playback</code> 的职责（如状态快照构建、revision 生成）移入了 runtime？这是禁止的。</li></ol><p>runtime 过渡期内，<code>XiaoMusic</code> 类仍承担部分协调职责，改动前需评估该职责最终应下沉到哪个边界。</p><hr><h2 id="_4-改-playback-前" tabindex="-1">4. 改 Playback 前 <a class="header-anchor" href="#_4-改-playback-前" aria-label="Permalink to &quot;4. 改 Playback 前&quot;">​</a></h2><p>必须确认：</p><ol><li>改动是否涉及 <code>build_player_state_snapshot()</code>？若是，必须同步阅读 <code>player_state_projection_spec.md</code>，确保快照输出符合全部字段规范。</li><li>改动是否影响 <code>revision</code> 递增逻辑或 <code>play_session_id</code> 切换逻辑？这两者的变化会直接影响前端状态消费，必须谨慎。</li><li><code>PlaybackFacade</code> 是 api 层调用播放能力的唯一入口，任何新的播放能力必须通过 facade 暴露，不得在 router 中直接调用 coordinator 或 transport。</li></ol><hr><h2 id="_5-改-auth-前" tabindex="-1">5. 改 Auth 前 <a class="header-anchor" href="#_5-改-auth-前" aria-label="Permalink to &quot;5. 改 Auth 前&quot;">​</a></h2><p>必须确认：</p><ol><li>该改动是否影响两层认证状态的边界（长期态 / 短期态）？见 <code>authentication_architecture.md</code>。</li><li><code>auth.json</code> 是事实来源，任何认证状态的持久化必须通过 <code>TokenStore</code>，不得绕过。</li><li>认证恢复流程有固定步骤，改动前必须阅读 <code>auth_runtime_recovery.md</code>。</li></ol><hr><h2 id="_6-改-source-plugin-前" tabindex="-1">6. 改 Source / Plugin 前 <a class="header-anchor" href="#_6-改-source-plugin-前" aria-label="Permalink to &quot;6. 改 Source / Plugin 前&quot;">​</a></h2><p>必须确认：</p><ol><li>该改动是新增 source 类型，还是修改已有 source 内部实现？新增 source 类型必须在 <code>source_architecture.md</code> 确认规范，并更新 <code>api_v1_spec.md</code> 的 <code>source_hint</code> 允许值。修改已有 source 内部实现时，必须保持 <code>resolve()</code> 的返回类型不变。</li><li>新增的是 Source Plugin（正式体系）还是 MusicFree JS 插件（<code>site_media</code> 内部机制）？两者归属不同，见 <code>source_architecture.md</code> 第 5 节。</li><li>source 实现中是否出现了对 device、transport 或播放队列的直接调用？这是禁止的，必须移除。</li></ol><hr><h2 id="_7-改-webui-前" tabindex="-1">7. 改 WebUI 前 <a class="header-anchor" href="#_7-改-webui-前" aria-label="Permalink to &quot;7. 改 WebUI 前&quot;">​</a></h2><p>必须确认：</p><ol><li>该改动是否需要新的后端字段？若是，该字段必须先在 <code>api_v1_spec.md</code> 中声明，后端实现，最后前端消费——不得反向依赖未声明字段。</li><li>该改动是否引入了对播放状态的本地推算或补偿逻辑？这是禁止的，见 <code>webui_playback_state_machine_spec.md</code> 第 4 章。</li><li>歌单选中项同步是否仍基于 <code>track.id</code> 对照？不得回退为 <code>title</code> 文本匹配。</li><li>该改动是否在 SSE 连接正常时引入了并行轮询？这是禁止的。</li><li>改动是否读取了 <code>cur_music</code>、<code>is_playing</code>、<code>offset</code>、<code>duration</code> 等已废弃的兼容字段？这是禁止的。</li></ol><hr><h2 id="_8-新增模块的约束" tabindex="-1">8. 新增模块的约束 <a class="header-anchor" href="#_8-新增模块的约束" aria-label="Permalink to &quot;8. 新增模块的约束&quot;">​</a></h2><p>新增任何模块（文件、包、子系统）前，必须完成：</p><ol><li><strong>确认归属边界</strong>：在 <code>system_overview.md</code> 的九个一级边界中找到其归属，或判断是否需要新增边界（新增边界需同步更新 <code>system_overview.md</code>）。</li><li><strong>确认上游调用方</strong>：该模块由谁调用？通过什么接口？</li><li><strong>确认下游依赖</strong>：该模块依赖谁？是否跨越了边界约束？</li><li><strong>确认不越界</strong>：对照 <code>system_overview.md</code> 第 2 节的禁止调用规则。</li></ol><p>不允许边界不明直接落代码。如果不确定归属，先在架构文档中讨论确认，再写实现。</p><hr><h2 id="_9-文档更新规则" tabindex="-1">9. 文档更新规则 <a class="header-anchor" href="#_9-文档更新规则" aria-label="Permalink to &quot;9. 文档更新规则&quot;">​</a></h2><p>以下改动<strong>必须</strong>同步更新对应文档，不允许代码与文档脱节：</p><table tabindex="0"><thead><tr><th>改动类型</th><th>必须更新的文档</th></tr></thead><tbody><tr><td>新增 v1 接口或修改接口契约</td><td><code>docs/api/api_v1_spec.md</code></td></tr><tr><td>修改播放状态快照字段或语义</td><td><code>docs/spec/player_state_projection_spec.md</code></td></tr><tr><td>修改 SSE 事件格式或推送规则</td><td><code>docs/spec/player_stream_sse_spec.md</code></td></tr><tr><td>修改 source 类型集合</td><td><code>docs/architecture/source_architecture.md</code></td></tr><tr><td>修改 WebUI 接口依赖</td><td><code>docs/architecture/webui_architecture.md</code></td></tr><tr><td>修改认证恢复流程</td><td><code>docs/spec/auth_runtime_recovery.md</code></td></tr><tr><td>修改系统一级边界</td><td><code>docs/architecture/system_overview.md</code></td></tr></tbody></table><p>以下改动<strong>不需要</strong>更新规范文档（属于内部实现细节）：</p><ul><li>source 插件内部解析逻辑调整（接口不变）</li><li>transport 内部重试策略调整</li><li>日志格式调整</li><li>测试文件新增</li></ul><hr><h2 id="_10-文档冲突裁决" tabindex="-1">10. 文档冲突裁决 <a class="header-anchor" href="#_10-文档冲突裁决" aria-label="Permalink to &quot;10. 文档冲突裁决&quot;">​</a></h2><p>当不同文档对同一事项有不同描述时，按以下优先级裁决（从高到低）：</p><ol><li><code>docs/api/api_v1_spec.md</code></li><li><code>docs/spec/*</code></li><li><code>docs/architecture/*</code></li><li><code>docs/development/*</code></li><li><code>ARCHITECTURE.md</code></li><li><code>docs/dev/*</code>（历史归档，不作为当前依据）</li></ol><p>发现文档冲突时，以高优先级文档为准，并将低优先级文档中的冲突内容标记为待修正，在下一轮文档更新中处理。</p><hr><h2 id="_11-ai-执行规则" tabindex="-1">11. AI 执行规则 <a class="header-anchor" href="#_11-ai-执行规则" aria-label="Permalink to &quot;11. AI 执行规则&quot;">​</a></h2><p>当 AI（Codex、Claude 等）执行代码改动任务时，必须遵守本指南的全部规则，且：</p><ul><li>不得以&quot;实现上更简单&quot;为由跳过归属边界确认</li><li>不得假设某字段存在于 API 响应中（必须查 <code>api_v1_spec.md</code> 确认）</li><li>不得修改 <code>docs/dev/*</code> 中的历史归档文档（只读）</li><li>改动文档时，必须更新文档头部的&quot;最后更新&quot;日期</li><li>改动涉及多个边界时，必须分步执行，每步明确指出影响边界</li></ul><hr><h2 id="_12-快速检查清单" tabindex="-1">12. 快速检查清单 <a class="header-anchor" href="#_12-快速检查清单" aria-label="Permalink to &quot;12. 快速检查清单&quot;">​</a></h2><p>改代码之前，回答这五个问题：</p><ol><li><strong>这个改动属于哪个边界？</strong>（对照 <code>system_overview.md</code> 九个一级边界）</li><li><strong>改动前我读了哪些规范文档？</strong>（对照第 1 节改动前置规则总表）</li><li><strong>这个改动是否会影响对外接口契约？</strong>（若是，先更新 <code>api_v1_spec.md</code>）</li><li><strong>这个改动是否跨越了边界禁止规则？</strong>（对照 <code>system_overview.md</code> 第 2 节）</li><li><strong>改完之后需要更新哪些文档？</strong>（对照第 9 节文档更新规则）</li></ol><p>五个问题全部能回答，才开始写代码。</p>',57)]))}const h=t(r,[["render",i]]);export{_ as __pageData,h as default};
